userDefinedLinkHintCss:
/*
Cobalt2 theme for Vimium
To use:
  1. Copy the code.
  2. Go to the Vimium options.
  3. Click Show Advanced Options.
  4. Under Advanced Options, scroll down to CSS for link hints.
  5. Paste the code in the text field.
  6. Click Save Changes.
  7. Go to the website of your choice (or, if you have it open already, reload it) and check out the results.
*/

/* Link hint boxes */
div > .vimiumHintMarker {
  background: #0e3a59;
  font-size: 12px;
  border: 0.25em solid #193549;
  border-radius: 0.34em;
  box-shadow: 0em 0.1em 0.6em 0.1em rgba(0, 0, 0, 0.4);
}

/* Link hint text */
div > .vimiumHintMarker span {
  color: #ffffff;
  font-size: inherit;
  text-shadow: none;
}

/* Link hint matching characters */
div > .vimiumHintMarker > .matchingCharacter {
  color: #1478db;
}

/* HUD ("heads-up display") bar */
div.vimiumHUD {
  background: #193549;
  border: none;
}

div.vimiumHUD .vimiumHUDSearchArea {
  background: #193549;
}

div.vimiumHUD .hud-find {
  background: #193549;
  border: none;
  color: #ffffff;
}

div.vimiumHUD span#hud-find-input {
  color: #ffffff; /* 'Foreground' color */
}

div.vimiumHUD span#hud-match-count {
  color: #1478db; /* 'Comment' color */
}

div.vimiumHUD .vimiumHUDSearchAreaInner {
  color: #1478db; /* 'Comment' color */
}

#vomnibar {
  background-color: #193549;
}

#vomnibar input {
  color: #ffffff;
  font: -moz-window;
  /*font-family: 'Helvetica Neue', Helvetica, Arial, sans-serif;*/
  font-size: 20px;
  height: 34px;
  margin-bottom: 0;
  padding: 4px;
  background-color: #0e3a59;
  border: none;
  width: 100%;
  outline: none;
}

#vomnibar .vomnibarSearchArea {
  display: block;
  padding: 5x;
  background-color: #0e3a59;
  border-bottom: none;
}

#vomnibar ul {
  background-color: #193549;
  list-style: none;
  padding-top: 0;
  padding-bottom: 2x;
  margin-block-start: 2px;
  margin-block-end: 0px;
}

#vomnibar li {
  line-height: 1.1em;
  padding: 7px 10px;
  font-size: 16px;
  color: #ffffff;
  position: relative;
  display: list-item;
  margin: auto;
}

#vomnibar li .vomnibarBottomHalf {
  font-size: 15px;
  margin-top: 3px;
  padding: 2px 0;
}

#vomnibar li .vomnibarSource {
  color: #3ad900;
  margin-right: 4px;
}
#vomnibar li .vomnibarRelevancy {
  position: absolute;
  right: 0;
  top: 0;
  padding: 5px;
  background-color: #193549;
  color: #ffffff;
  font-family: monospace;
  width: 100px;
  overflow: hidden;
}

#vomnibar li .vomnibarUrl {
  white-space: nowrap;
  color: #1478db;
}

#vomnibar li .vomnibarMatch {
  font-weight: bold;
  color: #ff9d00;
}

#vomnibar li em,
#vomnibar li .vomnibarTitle {
  color: #ffffff;
  margin-left: 4px;
  font-weight: normal;
}
#vomnibar li em {
  font-style: italic;
}
#vomnibar li em .vomnibarMatch,
#vomnibar li .vomnibarTitle .vomnibarMatch {
  color: #ffc600;
}

#vomnibar li.vomnibarSelected {
  background-color: #275d84;
  font-weight: normal;
}

#vomnibarInput::selection {
  background-color: #a5ff90;
}
